/**
 * Set of terms that need IDF recalculation.
 * Deferred recalc avoids overhead on frequent updates.
 */
private dirtyTerms: Set<string> = new Set();

/**
 * Total document count for IDF calculation.
 * Cached to avoid recounting on every update.
 */
private documentCount: number = 0;

/**
 * Add a single entity to the index incrementally.
 *
 * O(log n) operation - only updates the document vector for the new entity
 * and marks affected terms as dirty for lazy IDF recalculation.
 *
 * @param entity - Entity to add to the index
 * @returns True if added, false if entity already indexed
 */
addEntity(entity: Entity): boolean {
  if (!this.index) {
    // No index exists - caller should build first
    return false;
  }

  if (this.index.documents.has(entity.name)) {
    // Already indexed
    return false;
  }

  // Build document text and tokenize
  const documentText = [
    entity.name,
    entity.entityType,
    ...entity.observations,
  ].join(' ');

  const tokens = tokenize(documentText);
  const tokenSet = new Set(tokens);

  // Calculate term frequencies
  const termFreq: Record<string, number> = {};
  for (const term of tokens) {
    termFreq[term] = (termFreq[term] || 0) + 1;
    // Mark term as dirty for IDF recalc
    this.dirtyTerms.add(term);
  }

  // Add document vector
  this.index.documents.set(entity.name, {
    entityName: entity.name,
    terms: termFreq,
    documentText,
  });

  this.documentCount++;
  this.index.lastUpdated = new Date().toISOString();

  return true;
}

/**
 * Remove a single entity from the index incrementally.
 *
 * O(log n) operation - removes the document vector and marks affected
 * terms as dirty for lazy IDF recalculation.
 *
 * @param entityName - Name of entity to remove
 * @returns True if removed, false if entity not in index
 */
removeEntity(entityName: string): boolean {
  if (!this.index) {
    return false;
  }

  const doc = this.index.documents.get(entityName);
  if (!doc) {
    return false;
  }

  // Mark all terms from this document as dirty
  for (const term of Object.keys(doc.terms)) {
    this.dirtyTerms.add(term);
  }

  // Remove document vector
  this.index.documents.delete(entityName);
  this.documentCount--;
  this.index.lastUpdated = new Date().toISOString();

  return true;
}

/**
 * Update a single entity in the index incrementally.
 *
 * Combines remove + add for atomic update. If entity doesn't exist,
 * performs add only.
 *
 * @param entity - Entity with updated data
 * @returns True if index was modified
 */
updateEntityInIndex(entity: Entity): boolean {
  if (!this.index) {
    return false;
  }

  // Remove old version (if exists) then add new
  this.removeEntity(entity.name);
  return this.addEntity(entity);
}

/**
 * Recalculate IDF values for dirty terms.
 *
 * Called lazily before search operations to ensure IDF values are accurate.
 * Uses the existing document vectors to count term occurrences.
 *
 * @returns Number of terms recalculated
 */
recalculateDirtyIDF(): number {
  if (!this.index || this.dirtyTerms.size === 0) {
    return 0;
  }

  const totalDocs = this.index.documents.size;
  if (totalDocs === 0) {
    // Clear IDF if no documents
    this.index.idf.clear();
    this.dirtyTerms.clear();
    return 0;
  }

  let recalculated = 0;

  for (const term of this.dirtyTerms) {
    // Count documents containing this term
    let docFreq = 0;
    for (const doc of this.index.documents.values()) {
      if (term in doc.terms) {
        docFreq++;
      }
    }

    if (docFreq === 0) {
      // Term no longer in any document, remove from IDF
      this.index.idf.delete(term);
    } else {
      // Recalculate IDF: log(totalDocs / docFreq)
      const idfValue = Math.log(totalDocs / docFreq);
      this.index.idf.set(term, idfValue);
    }
    recalculated++;
  }

  this.dirtyTerms.clear();
  this.index.lastUpdated = new Date().toISOString();

  return recalculated;
}

/**
 * Check if there are terms pending IDF recalculation.
 *
 * @returns True if recalculateDirtyIDF() should be called before search
 */
hasDirtyTerms(): boolean {
  return this.dirtyTerms.size > 0;
}

/**
 * Get count of dirty terms pending recalculation.
 */
getDirtyTermCount(): number {
  return this.dirtyTerms.size;
}

