if (this.events) {
  this.subscribeToEvents(this.events);
}

/**
 * Subscribe to graph events for incremental index updates.
 * @private
 */
private subscribeToEvents(events: GraphEventEmitter): void {
  // Handle entity creation
  events.on('entityCreated', (event: EntityCreatedEvent) => {
    if (this.indexManager?.getIndex()) {
      this.indexManager.addEntity(event.entity);
    }
  });

  // Handle entity update
  events.on('entityUpdated', (event: EntityUpdatedEvent) => {
    if (this.indexManager?.getIndex()) {
      this.indexManager.updateEntityInIndex(event.entity);
    }
  });

  // Handle entity deletion
  events.on('entityDeleted', (event: EntityDeletedEvent) => {
    if (this.indexManager?.getIndex()) {
      this.indexManager.removeEntity(event.entityName);
    }
  });
}

