import { describe, it, expect, beforeEach } from 'vitest';
import { TFIDFIndexManager } from '../../../src/search/TFIDFIndexManager.js';
import type { Entity, ReadonlyKnowledgeGraph } from '../../../src/types/types.js';
import { join } from 'path';
import { tmpdir } from 'os';

const createTestGraph = (entities: Entity[]): ReadonlyKnowledgeGraph => ({
  entities,
  relations: [],
});

const createEntity = (name: string, observations: string[]): Entity => ({
  name,
  entityType: 'test',
  observations,
  createdAt: new Date().toISOString(),
  lastModified: new Date().toISOString(),
});

describe('TFIDFIndexManager Incremental Updates', () => {
  let manager: TFIDFIndexManager;
  const testDir = join(tmpdir(), `tfidf-test-${Date.now()}`);

  beforeEach(async () => {
    manager = new TFIDFIndexManager(testDir);
    // Build initial index with some entities
    const graph = createTestGraph([
      createEntity('Entity1', ['hello world']),
      createEntity('Entity2', ['foo bar']),
      createEntity('Entity3', ['hello foo']),
    ]);
    await manager.buildIndex(graph);
  });

  describe('addEntity', () => {
    it('should add a new entity to the index', () => {
      const newEntity = createEntity('Entity4', ['new content baz']);

      const result = manager.addEntity(newEntity);

      expect(result).toBe(true);
      const index = manager.getIndex();
      expect(index?.documents.has('Entity4')).toBe(true);
      expect(index?.documents.get('Entity4')?.terms).toHaveProperty('new');
    });

    it('should mark new terms as dirty', () => {
      const newEntity = createEntity('Entity4', ['unique term xyz']);

      expect(manager.getDirtyTermCount()).toBe(0);
      manager.addEntity(newEntity);

      expect(manager.hasDirtyTerms()).toBe(true);
      expect(manager.getDirtyTermCount()).toBeGreaterThan(0);
    });

    it('should not add duplicate entity', () => {
      const result = manager.addEntity(createEntity('Entity1', ['different']));

      expect(result).toBe(false);
    });

    it('should return false when no index exists', () => {
      const freshManager = new TFIDFIndexManager(testDir);
      const result = freshManager.addEntity(createEntity('Test', ['content']));

      expect(result).toBe(false);
    });
  });

  describe('removeEntity', () => {
    it('should remove an entity from the index', () => {
      const result = manager.removeEntity('Entity1');

      expect(result).toBe(true);
      const index = manager.getIndex();
      expect(index?.documents.has('Entity1')).toBe(false);
    });

    it('should mark removed terms as dirty', () => {
      manager.removeEntity('Entity1');

      expect(manager.hasDirtyTerms()).toBe(true);
    });

    it('should return false for non-existent entity', () => {
      const result = manager.removeEntity('NonExistent');

      expect(result).toBe(false);
    });
  });

  describe('updateEntityInIndex', () => {
    it('should update an existing entity', () => {
      const updatedEntity = createEntity('Entity1', ['updated observations']);

      const result = manager.updateEntityInIndex(updatedEntity);

      expect(result).toBe(true);
      const doc = manager.getIndex()?.documents.get('Entity1');
      expect(doc?.terms).toHaveProperty('updated');
      expect(doc?.terms).not.toHaveProperty('hello');
    });

    it('should add entity if it does not exist', () => {
      const newEntity = createEntity('Entity5', ['brand new']);

      const result = manager.updateEntityInIndex(newEntity);

      expect(result).toBe(true);
      expect(manager.getIndex()?.documents.has('Entity5')).toBe(true);
    });
  });
});

describe('Dirty IDF Recalculation', () => {
  let manager: TFIDFIndexManager;
  const testDir = join(tmpdir(), `tfidf-idf-test-${Date.now()}`);

  beforeEach(async () => {
    manager = new TFIDFIndexManager(testDir);
    const graph = createTestGraph([
      createEntity('Doc1', ['apple banana']),
      createEntity('Doc2', ['banana cherry']),
      createEntity('Doc3', ['cherry apple']),
    ]);
    await manager.buildIndex(graph);
  });

  it('should recalculate IDF for dirty terms only', () => {
    // Add entity with new term
    manager.addEntity(createEntity('Doc4', ['dragonfruit']));

    expect(manager.hasDirtyTerms()).toBe(true);

    const recalculated = manager.recalculateDirtyIDF();

    expect(recalculated).toBeGreaterThan(0);
    expect(manager.hasDirtyTerms()).toBe(false);
    expect(manager.getIndex()?.idf.has('dragonfruit')).toBe(true);
  });

  it('should update IDF when document frequency changes', () => {
    const idfBefore = manager.getIndex()?.idf.get('apple');

    // Add another document with 'apple'
    manager.addEntity(createEntity('Doc4', ['apple pie']));
    manager.recalculateDirtyIDF();

    const idfAfter = manager.getIndex()?.idf.get('apple');

    // IDF should decrease as term appears in more documents
    expect(idfAfter).toBeLessThan(idfBefore!);
  });

  it('should remove IDF entry when term no longer exists', () => {
    // Remove all entities containing 'apple'
    manager.removeEntity('Doc1');
    manager.removeEntity('Doc3');
    manager.recalculateDirtyIDF();

    // 'apple' should no longer be in IDF (only Doc1 and Doc3 had it)
    expect(manager.getIndex()?.idf.has('apple')).toBe(false);
  });

  it('should handle empty index gracefully', () => {
    manager.removeEntity('Doc1');
    manager.removeEntity('Doc2');
    manager.removeEntity('Doc3');

    const recalculated = manager.recalculateDirtyIDF();

    expect(recalculated).toBeGreaterThan(0);
    expect(manager.getIndex()?.idf.size).toBe(0);
  });
});

describe('Performance', () => {
  const testDir = join(tmpdir(), `tfidf-perf-test-${Date.now()}`);

  it('should be faster than full rebuild for single entity update', async () => {
    const manager = new TFIDFIndexManager(testDir);

    // Create graph with 500 entities
    const entities = Array.from({ length: 500 }, (_, i) =>
      createEntity(`Entity${i}`, [`observation ${i} with some content and words`])
    );
    const graph = createTestGraph(entities);

    // Build initial index
    await manager.buildIndex(graph);

    // Time incremental update
    const incrementalStart = Date.now();
    manager.addEntity(createEntity('NewEntity', ['brand new content here']));
    manager.recalculateDirtyIDF();
    const incrementalTime = Date.now() - incrementalStart;

    // Time full rebuild
    const updatedGraph = createTestGraph([...entities, createEntity('NewEntity2', ['another new one'])]);
    const rebuildStart = Date.now();
    await manager.buildIndex(updatedGraph);
    const rebuildTime = Date.now() - rebuildStart;

    console.log(`Incremental update: ${incrementalTime}ms, Full rebuild: ${rebuildTime}ms`);

    // Incremental should be significantly faster
    expect(incrementalTime).toBeLessThan(rebuildTime);
  });
});
